import{_ as i,W as e,X as l,Y as t}from"./framework-9a5142fa.js";const a={},n=t('<h2 id="windows-10" tabindex="-1"><a class="header-anchor" href="#windows-10" aria-hidden="true">#</a> Windows 10</h2><ul><li><strong>打开设置</strong>： <ul><li>点击Windows菜单左下角的开始按钮，然后选择“设置”。</li><li>或者点击右下角的通知按钮，选择“所有设置”。</li><li>也可以使用快捷键【Win+i】直接打开设置界面。</li></ul></li><li><strong>调整多任务处理设置</strong>： <ul><li>在设置界面中，找到并点击“系统”选项（在某些版本中可能直接显示为“多任务处理”）。</li><li>查找与Alt+Tab相关的设置，通常位于“多任务”或“多任务处理”部分。</li><li>修改Alt+Tab设置，选择“仅打开的窗口”。这样，使用Alt+Tab切换时就不会显示Edge浏览器的每个标签页，而是整个Edge浏览器窗口。</li></ul></li></ul><h2 id="windows-11系统" tabindex="-1"><a class="header-anchor" href="#windows-11系统" aria-hidden="true">#</a> Windows 11系统</h2><p><img src="https://cdn.jsdelivr.net/gh/sword4869/pic1@main/images/202502111104410.png" alt="img"></p>',4),s=[n];function _(d,o){return e(),l("div",null,s)}const c=i(a,[["render",_],["__file","Alt_Tab切窗口取消掉Edge浏览器的多标签页问题.html.vue"]]);export{c as default};
